import type { AgentRunOptions } from '../types.js';
import type { Profile } from './types.js';
import type { Tool } from '../../tools/types.js';

/**
 * ProfileLoader merges profile settings into AgentRunOptions.
 */
export class ProfileLoader {
  /**
   * Merge a profile into the base agent run options.
   *
   * Merging rules:
   * - systemPromptAppend: appended to existing systemPrompt with double newline
   * - tools: enabled/disabled overrides are applied to the tool list
   * - model: overrides the model if set
   * - maxIterations: overrides maxIterations if set
   *
   * @param baseOptions - The base agent run options to merge into
   * @param profile - The profile to apply
   * @returns New AgentRunOptions with profile settings merged
   */
  static merge(baseOptions: AgentRunOptions, profile: Profile): AgentRunOptions {
    const merged: AgentRunOptions = { ...baseOptions };

    // Append system prompt
    if (profile.systemPromptAppend) {
      merged.systemPrompt = baseOptions.systemPrompt
        ? `${baseOptions.systemPrompt}\n\n${profile.systemPromptAppend}`
        : profile.systemPromptAppend;
    }

    // Apply tool overrides
    if (profile.tools) {
      merged.tools = this.applyToolOverrides(
        baseOptions.tools,
        profile.tools.enabled ?? [],
        profile.tools.disabled ?? []
      );
    }

    // Override model
    if (profile.model) {
      merged.model = profile.model;
    }

    // Override maxIterations
    if (profile.maxIterations !== undefined) {
      merged.maxIterations = profile.maxIterations;
    }

    return merged;
  }

  /**
   * Apply tool enable/disable overrides to a tool list.
   */
  private static applyToolOverrides(
    tools: Tool[],
    enabled: string[],
    disabled: string[]
  ): Tool[] {
    // Build a set of all tool names from the original list
    const allTools = new Map(tools.map(t => [t.name, t]));

    // If enabled list is provided, start with only those tools
    if (enabled.length > 0) {
      const enabledSet = new Set(enabled);
      return tools.filter(t => enabledSet.has(t.name));
    }

    // If disabled list is provided, filter out those tools
    if (disabled.length > 0) {
      const disabledSet = new Set(disabled);
      return tools.filter(t => !disabledSet.has(t.name));
    }

    // No overrides, return original
    return tools;
  }

  /**
   * Create a profile from current agent run options.
   * Used by the "profile save" command to capture current session state.
   */
  static createFromOptions(
    name: string,
    description: string,
    options: AgentRunOptions,
    tags: string[] = []
  ): Profile {
    return {
      name,
      description,
      model: options.model,
      maxIterations: options.maxIterations,
      tools: {
        enabled: options.tools.map(t => t.name),
      },
      tags,
      // Note: systemPromptAppend is not captured from options since we don't
      // know which part was the base vs. appended. User would need to manually
      // set this when creating a profile.
    };
  }
}

import { loadContextFile } from './ContextLoader.js';
import { DecisionStore } from '../decisions/DecisionStore.js';
import type { Decision } from '../decisions/types.js';
import type { Constraint } from '../constraints/types.js';

interface ContextBuildOptions {
  contextFilePath: string;
  systemPromptFile?: string | null;
  projectRoot?: string | null;
  blockConstraints?: Constraint[];
  warnConstraints?: Constraint[];
}

const DEFAULT_SYSTEM_PROMPT = `You are EPAM CLI, an AI coding assistant running in the terminal. You have access to tools to read files, write files, search code, and execute commands. Be concise and helpful. When asked to perform tasks, prefer using tools over explaining what to do.`;

async function loadRelevantDecisions(projectRoot: string | null): Promise<Decision[]> {
  if (!projectRoot) {
    return [];
  }

  try {
    const store = new DecisionStore(projectRoot);
    const allDecisions = await store.list();

    // Return the 5 most recent decisions
    return allDecisions
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      .slice(0, 5);
  } catch {
    // Gracefully handle missing or malformed decisions file
    return [];
  }
}

function formatDecisionsBlock(decisions: Decision[]): string {
  if (decisions.length === 0) {
    return '';
  }

  const lines = ['[DECISION RECORDS]', ''];

  for (const decision of decisions) {
    lines.push(`Decision ${decision.id}: ${decision.title}`);
    if (decision.description) {
      lines.push(`Description: ${decision.description}`);
    }
    lines.push(`Rationale: ${decision.rationale}`);
    lines.push(`Pattern to avoid: ${decision.pattern_to_avoid}`);
    lines.push(`Approved alternative: ${decision.approved_alternative}`);
    if (decision.tags.length > 0) {
      lines.push(`Tags: ${decision.tags.join(', ')}`);
    }
    lines.push('');
  }

  return lines.join('\n');
}

function formatBlockConstraints(constraints: Constraint[]): string {
  if (constraints.length === 0) {
    return '';
  }

  const lines = ['[CONSTRAINTS — MUST FOLLOW]', ''];

  for (const constraint of constraints) {
    lines.push(`- ${constraint.rule}`);
  }

  lines.push('');
  return lines.join('\n');
}

function formatWarnConstraints(constraints: Constraint[]): string {
  if (constraints.length === 0) {
    return '';
  }

  const lines = ['[ADVISORY CONSTRAINTS]', ''];

  for (const constraint of constraints) {
    lines.push(`- ${constraint.rule}`);
  }

  lines.push('');
  return lines.join('\n');
}

export async function buildSystemPrompt(opts: ContextBuildOptions): Promise<string> {
  const parts: string[] = [];

  // Base system prompt
  if (opts.systemPromptFile) {
    const custom = await loadContextFile(opts.systemPromptFile);
    if (custom) {
      parts.push(custom);
    } else {
      parts.push(DEFAULT_SYSTEM_PROMPT);
    }
  } else {
    parts.push(DEFAULT_SYSTEM_PROMPT);
  }

  // Block-severity constraints (injected prominently at the top)
  if (opts.blockConstraints && opts.blockConstraints.length > 0) {
    const blockConstraintsBlock = formatBlockConstraints(opts.blockConstraints);
    parts.push(`\n${blockConstraintsBlock}`);
  }

  // Decision records (injected early so they influence behavior)
  const decisions = await loadRelevantDecisions(opts.projectRoot ?? null);
  const decisionsBlock = formatDecisionsBlock(decisions);
  if (decisionsBlock) {
    parts.push(`\n${decisionsBlock}`);
  }

  // Project context
  const contextMd = await loadContextFile(opts.contextFilePath);
  if (contextMd) {
    parts.push(`\n## Project Context\n\n${contextMd}`);
  }

  if (opts.projectRoot) {
    parts.push(`\nWorking directory: ${opts.projectRoot}`);
  }

  // Warn-severity constraints (injected at the bottom as advisory notes)
  if (opts.warnConstraints && opts.warnConstraints.length > 0) {
    const warnConstraintsBlock = formatWarnConstraints(opts.warnConstraints);
    parts.push(`\n${warnConstraintsBlock}`);
  }

  return parts.join('\n');
}

import type { LLMProvider, TokenUsage, Message } from '../providers/types.js';
import type { Tool } from '../tools/types.js';
import type { BudgetGuard, BudgetCheckResult } from '../billing/BudgetGuard.js';

export interface AgentRunOptions {
  userMessage: string;
  systemPrompt: string;
  provider: LLMProvider;
  model: string;
  tools: Tool[];
  maxIterations?: number;
  /** Prior conversation history to prepend before the current user message. */
  history?: Message[];
  /** Token threshold at which the runner auto-compresses older messages. */
  autoCompressAt?: number;
  /** Max characters per tool result before truncation (default: 32768). */
  maxToolOutputChars?: number;
  /** Maximum output tokens per LLM response (default: 16384). */
  maxOutputTokens?: number;
  /** Skip interactive tool approval prompts (for CI/non-interactive use). */
  dangerousSkipApproval?: boolean;
  /** Shared budget guard instance for cross-turn cost enforcement. */
  budgetGuard?: BudgetGuard;
  onTextDelta?: (delta: string) => void;
  onToolCall?: (toolName: string, input: Record<string, unknown>) => void;
  onToolResult?: (toolName: string, result: string, isError: boolean) => void;
  onIterationStart?: (iteration: number) => void;
  /** Fired when a budget threshold is crossed (warning, downgrade, or pause). */
  onBudgetCheck?: (result: BudgetCheckResult) => void;
  /**
   * Fired before returning the final result. Allows auditors to review the response.
   * Should return true to proceed with the response, false to block it.
   */
  onAuditorReview?: (
    userMessage: string,
    proposedResponse: string,
    messages: Message[],
  ) => Promise<boolean>;
}

export interface AgentRunResult {
  finalResponse: string;
  toolCallCount: number;
  iterations: number;
  usage: TokenUsage;
  /** Full message array at end of run, including history + this turn's exchanges. */
  messages: Message[];
}

