import fs from 'fs/promises';
import path from 'path';
import { pathExists, readJsonFile } from '../utils/fs.js';

interface SyncState {
  lastPushTimestamp: string | null;
  lastPullTimestamp: string | null;
  projectId: string | null;
}

export async function loadContextFile(contextFilePath: string): Promise<string> {
  if (!contextFilePath) return '';

  const resolved = path.resolve(contextFilePath);
  if (!(await pathExists(resolved))) return '';

  try {
    const content = await fs.readFile(resolved, 'utf-8');
    return content.trim();
  } catch {
    return '';
  }
}

/**
 * Check if remote context is available and more recent than local
 * This is called at startup to ensure the context includes remote updates
 */
export async function checkRemoteContext(projectRoot: string | null): Promise<boolean> {
  if (!projectRoot) return false;

  const syncStatePath = path.join(projectRoot, '.epam', '.sync-state.json');
  const syncState = await readJsonFile<SyncState>(syncStatePath);

  if (!syncState || !syncState.lastPullTimestamp) {
    return false;
  }

  // Check if local files exist and when they were last modified
  const contextPath = path.join(projectRoot, '.epam', 'context.md');
  const decisionsPath = path.join(projectRoot, '.epam', 'decisions.jsonl');

  let localLatest = 0;

  if (await pathExists(contextPath)) {
    const stats = await fs.stat(contextPath);
    localLatest = Math.max(localLatest, stats.mtimeMs);
  }

  if (await pathExists(decisionsPath)) {
    const stats = await fs.stat(decisionsPath);
    localLatest = Math.max(localLatest, stats.mtimeMs);
  }

  const remotePulledAt = new Date(syncState.lastPullTimestamp).getTime();

  // If remote was pulled and local hasn't been modified since, context is up-to-date
  return localLatest <= remotePulledAt;
}

/**
 * Agent profile schema for saving/loading session configurations.
 */
export interface Profile {
  /** Profile identifier (used as filename without extension). */
  name: string;
  /** Human-readable description of the profile's purpose. */
  description: string;
  /** Additional system prompt text to append to the base system prompt. */
  systemPromptAppend?: string;
  /** Tool enable/disable overrides. */
  tools?: {
    enabled?: string[];
    disabled?: string[];
  };
  /** Model override (e.g., "claude-sonnet-4-6"). */
  model?: string;
  /** Max iterations override. */
  maxIterations?: number;
  /** Tags for filtering/categorizing profiles. */
  tags?: string[];
}

/**
 * Profile with its source location (global vs project-local).
 */
export interface ProfileWithSource extends Profile {
  source: 'global' | 'local';
  filePath: string;
}

import path from 'path';
import { appendLine, readLines, ensureDir } from '../utils/fs.js';
import type { Decision } from './types.js';

export class DecisionStore {
  private decisionsPath: string;

  constructor(projectRoot: string) {
    this.decisionsPath = path.join(projectRoot, '.epam', 'decisions.jsonl');
  }

  /**
   * Add a new decision record with auto-generated ID
   */
  async add(decision: Omit<Decision, 'id' | 'createdAt'>): Promise<Decision> {
    const existingDecisions = await this.list();
    const nextId = this.generateNextId(existingDecisions);

    const newDecision: Decision = {
      ...decision,
      id: nextId,
      createdAt: new Date().toISOString(),
    };

    await ensureDir(path.dirname(this.decisionsPath));
    await appendLine(this.decisionsPath, newDecision);

    return newDecision;
  }

  /**
   * List all decisions
   */
  async list(): Promise<Decision[]> {
    const lines = await readLines(this.decisionsPath);
    return lines
      .map(line => {
        try {
          return JSON.parse(line) as Decision;
        } catch {
          return null;
        }
      })
      .filter((d): d is Decision => d !== null);
  }

  /**
   * Search decisions by keyword (case-insensitive match on title, description, tags)
   */
  async search(query: string): Promise<Decision[]> {
    const allDecisions = await this.list();
    const lowerQuery = query.toLowerCase();

    return allDecisions.filter(decision => {
      const titleMatch = decision.title.toLowerCase().includes(lowerQuery);
      const descriptionMatch = decision.description?.toLowerCase().includes(lowerQuery) ?? false;
      const tagsMatch = decision.tags.some(tag => tag.toLowerCase().includes(lowerQuery));

      return titleMatch || descriptionMatch || tagsMatch;
    });
  }

  /**
   * Generate next sequential ID (DEC-001, DEC-002, etc.)
   */
  private generateNextId(existingDecisions: Decision[]): string {
    if (existingDecisions.length === 0) {
      return 'DEC-001';
    }

    // Extract numeric part from IDs and find max
    const numbers = existingDecisions
      .map(d => {
        const match = d.id.match(/^DEC-(\d+)$/);
        return match ? parseInt(match[1], 10) : 0;
      })
      .filter(n => n > 0);

    const maxNumber = Math.max(0, ...numbers);
    const nextNumber = maxNumber + 1;

    return `DEC-${String(nextNumber).padStart(3, '0')}`;
  }
}

export interface Decision {
  id: string;
  title: string;
  description?: string;
  rationale: string;
  pattern_to_avoid: string;
  approved_alternative: string;
  tags: string[];
  author: string;
  createdAt: string;
}

