import { SearchTool } from '../../tools/builtin/Search.js';
import { FetchUrlTool } from '../../tools/builtin/FetchUrl.js';
import { Repl } from '../repl/Repl.js';
import { PipeWriter } from '../output/PipeWriter.js';
import { AgentRunner } from '../../agent/AgentRunner.js';
import { buildSystemPrompt } from '../../context/ContextBuilder.js';
import { ProviderChain } from '../../providers/ProviderChain.js';
import { getApiKey as getEnvApiKey } from '../../config/EnvVarOverrides.js';
import { resolveProviderSecret } from '../../auth/ProviderCredentialStore.js';
import { detectTier } from '../../billing/TierDetector.js';
import { McpClient } from '../../mcp/McpClient.js';

const VERSION = '0.1.0';

export function createChatCommand(): Command {
  return new Command('chat')
    .description('Start an interactive chat session')
    .option('-m, --model <model>', 'Model to use')
    .option('-p, --provider <provider>', 'Provider to use')
    .action(async (opts) => {
      const config = await resolveConfig({
        model: opts.model,
        provider: opts.provider,
      });

      const authManager = new AuthManager(config.backendUrl);
      const tier = await detectTier();

      // Build provider chain from llmChain config (up to 5 slots)
      const chain = new ProviderChain({
        slots: config.llmChain,
        resolveApiKey: async (providerName: string) => {
          return getEnvApiKey(providerName) ?? await resolveProviderSecret(providerName);
        },
        proxyConfig: (tier === 'pro' || tier === 'enterprise') ? {
          backendUrl: config.backendUrl,
          getAccessToken: () => authManager.getValidToken(),
        } : undefined,
      });
      await chain.initialize();

      // Fallback single provider (used for pipe mode and MemoryCompressor)
      const provider = chain;

      // Initialize MCP client and fetch remote tools
      const mcpClient = new McpClient(config.projectRoot ?? undefined);
      await mcpClient.initialize();
      const mcpTools = mcpClient.getTools();

      const tools = [
        new ReadFileTool(),
        new WriteFileTool(),
        new BashTool(),
        new ListFilesTool(),
        new SearchTool(),
        new FetchUrlTool(),
        ...mcpTools,
      ];

      if (!process.stdin.isTTY) {
        // Pipe mode: read stdin and run once
        const chunks: string[] = [];
        for await (const chunk of process.stdin) {
          chunks.push(chunk.toString());
        }
        const userMessage = chunks.join('').trim();
        if (!userMessage) process.exit(0);

        const systemPrompt = await buildSystemPrompt({
          contextFilePath: config.contextFile,
          systemPromptFile: config.systemPromptFile,
          projectRoot: config.projectRoot,
        });

        const writer = new PipeWriter();
        const runner = new AgentRunner({
          userMessage,
          systemPrompt,
          provider,
          model: config.model,
          tools,
          maxIterations: config.maxIterations,
          autoCompressAt: config.autoCompressAt,
          maxOutputTokens: config.maxOutputTokens,
          dangerousSkipApproval: config.tools.dangerousSkipApproval,
          onTextDelta: delta => writer.write(delta),
        });

        await runner.run();
        writer.finalize();
        return;
      }

      const repl = new Repl({ provider, tools, config, version: VERSION, providerChain: chain, mcpClient });
      await repl.start();
    });
}

import { findCommand } from './SlashCommands.js';
import type { SlashCommandContext } from './SlashCommands.js';

export type InputType = 'slash_command' | 'message' | 'empty';

export interface ParsedInput {
  type: InputType;
  raw: string;
  message?: string;
  slashCommand?: string;
  slashArgs?: string;
}

export function parseInput(raw: string): ParsedInput {
  const trimmed = raw.trim();

  if (!trimmed) {
    return { type: 'empty', raw };
  }

  if (trimmed.startsWith('/')) {
    const match = findCommand(trimmed);
    if (match) {
      return {
        type: 'slash_command',
        raw,
        slashCommand: match.command.name,
        slashArgs: match.args,
      };
    }
    // Unknown slash command — treat as message
  }

  return { type: 'message', raw, message: trimmed };
}

export async function handleSlashCommand(
  input: ParsedInput,
  ctx: SlashCommandContext
): Promise<boolean> {
  const match = findCommand(input.raw.trim());
  if (!match) {
    console.log(`Unknown command: ${input.raw.trim()}. Type /help for available commands.`);
    return true;
  }
  return match.command.execute(match.args, ctx);
}

