          profile.source === 'local' ? chalk.cyan('[local]') : chalk.dim('[global]');
        const tags =
          profile.tags && profile.tags.length > 0
            ? chalk.dim(` · ${profile.tags.join(', ')}`)
            : '';

        console.log(`  ${chalk.bold(profile.name)} ${sourceTag}${tags}`);
        console.log(`    ${chalk.dim(profile.description || '(no description)')}`);
      }
      console.log();
      console.log(chalk.dim('Use /profile <name> to load a profile'));
      console.log();
      return true;
