  async execute(args, ctx) {
    const userRequest = args.trim();

    if (!userRequest) {
      console.log(chalk.yellow('\nUsage: /plan <task description>'));
      console.log(chalk.dim('Example: /plan refactor the authentication module\n'));
      return true;
